  1→import { useState, useEffect, useRef, useCallback } from 'react';
  2→import styles from '../Universe.module.css';
  3→
  4→const RocketHUD = ({ rocketMode, onExit, onInteract }) => {
  5→    const [speed, setSpeed] = useState(0);
  6→    const [pitch, setPitch] = useState(0);
  7→    const [targetInfo, setTargetInfo] = useState(null);
  8→    const [distance, setDistance] = useState(null);
  9→    const [dockingState, setDockingState] = useState('none');
 10→    const pollRef = useRef(null);
 11→
 12→    // Poll refs at 10 Hz for HUD display
 13→    useEffect(() => {
 14→        pollRef.current = setInterval(() => {
 15→            setSpeed(rocketMode.getSpeedRatio());
 16→            setDockingState(rocketMode.getDockingState());
 17→
 18→            // Read pitch in degrees
 19→            if (rocketMode.pitch) {
 20→                setPitch(Math.round((rocketMode.pitch.current * 180) / Math.PI));
 21→            }
 22→
 23→            const idx = rocketMode.targetIndexRef.current;
 24→            const stars = rocketMode.starsRef.current;
 25→            if (idx >= 0 && idx < stars.length) {
 26→                const star = stars[idx];
 27→                setTargetInfo({ title: star.title, author: star.authorName });
 28→                setDistance(Math.round(star.viewZ * 7));
 29→            } else {
 30→                setTargetInfo(null);
 31→                setDistance(null);
 32→            }
 33→        }, 100);
 34→
 35→        return () => {
 36→            if (pollRef.current) clearInterval(pollRef.current);
 37→        };
 38→    }, [rocketMode]);
 39→
 40→    // Key bindings for Enter/Space (interact) and Escape (exit)
 41→    const handleKey = useCallback((e) => {
 42→        const ds = rocketMode.getDockingState();
 43→
 44→        // Suppress handled keys during approaching/flash (non-interruptible)
 45→        if (ds === 'approaching' || ds === 'flash') {
 46→            if (e.key === 'Enter' || e.key === ' ' || e.key === 'Escape') {
 47→                e.preventDefault();
 48→            }
 49→            return;
 50→        }
 51→
 52→        if (e.key === 'Enter' || e.key === ' ') {
 53→            e.preventDefault();
 54→            onInteract();
 55→        } else if (e.key === 'Escape') {
 56→            e.preventDefault();
 57→            // During magnet phase, abort docking instead of exiting
 58→            if (ds === 'magnet') {
 59→                rocketMode.abortDocking();
 60→            } else {
 61→                onExit();
 62→            }
 63→        }
 64→    }, [onInteract, onExit, rocketMode]);
 65→
 66→    useEffect(() => {
 67→        window.addEventListener('keydown', handleKey);
 68→        return () => window.removeEventListener('keydown', handleKey);
 69→    }, [handleKey]);
 70→
 71→    const absPitch = Math.abs(pitch);
 72→    const isDocking = dockingState === 'approaching' || dockingState === 'flash';
 73→
 74→    return (
 75→        <div className={styles.rocketHud}>
 76→            {/* Exit button */}
 77→            <button className={styles.rocketExitBtn} onClick={onExit} disabled={isDocking}>
 78→                <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" width="16" height="16" fill="currentColor">
 79→                    <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 80→                </svg>
 81→                Exit Rocket
 82→            </button>
 83→
 84→            {/* Pitch indicator (top-right, only when |pitch| > 5°) */}
 85→            {absPitch > 5 && (
 86→                <div className={styles.rocketPitch}>
 87→                    {pitch > 0 ? '\u2191' : '\u2193'} {absPitch}\u00B0
 88→                </div>
 89→            )}
 90→
 91→            {/* Target info (below center) */}
 92→            {targetInfo && (
 93→                <div className={styles.rocketTarget}>
 94→                    <div className={styles.rocketTargetTitle}>{targetInfo.title}</div>
 95→                    <div className={styles.rocketTargetAuthor}>by {targetInfo.author}</div>
 96→                    {distance != null && (
 97→                        <div className={styles.rocketTargetDistance}>{distance} LY</div>
 98→                    )}
 99→                    {isDocking ? (
100→                        <div className={styles.rocketTargetDocking}>DOCKING...</div>
101→                    ) : (
102→                        <div className={styles.rocketTargetPrompt}>Press ENTER to read</div>
103→                    )}
104→                </div>
105→            )}
106→
107→            {/* Speed bar */}
108→            <div className={styles.rocketSpeedBar}>
109→                <span className={styles.rocketSpeedLabel}>SPD</span>
110→                <div className={styles.rocketSpeedTrack}>
111→                    <div
112→                        className={styles.rocketSpeedFill}
113→                        style={{ width: `${Math.round(speed * 100)}%` }}
114→                    />
115→                </div>
116→                <span className={styles.rocketSpeedValue}>{Math.round(speed * 100)}%</span>
117→            </div>
118→
119→            {/* Controls hint */}
120→            <div className={styles.rocketControls}>
121→                <span>W/S Throttle</span>
122→                <span>A/D Yaw</span>
123→                <span>Q/E Pitch</span>
124→                <span>ENTER Read</span>
125→                <span>ESC Exit</span>
126→            </div>
127→        </div>
128→    );
129→};
130→
131→export default RocketHUD;
